import React, { useState, useMemo } from "react";
import { useTranslation } from "react-i18next";
import {
  theme, Row, Col, Card, Tree, Table, Button, Space, Typography,
  Tag, Input, Modal, Form, Select, Transfer, Popconfirm, Empty, Flex, App, Breadcrumb
} from "antd";
import {
  TeamOutlined, PlusOutlined, DeleteOutlined,
  EditOutlined, SearchOutlined, UserAddOutlined,
  ProjectOutlined, ClusterOutlined, DeploymentUnitOutlined, HomeOutlined
} from "@ant-design/icons";
import { initialTreeData, OrgNode, globalWorkerPool } from "../../../mocks/orgData";

const { useToken } = theme;
const { Title, Text } = Typography;
const { Option } = Select;

export default function OrganizationManagement() {
  const { token } = useToken();
  const { t } = useTranslation(["org", "common"]);
  const { message } = App.useApp();

  const [treeData, setTreeData] = useState<OrgNode[]>(initialTreeData);
  const [selectedKeys, setSelectedKeys] = useState<React.Key[]>([]);
  const [searchText, setSearchText] = useState("");
  const [expandedKeys, setExpandedKeys] = useState<React.Key[]>(["root"]);

  const [assignedMembers, setAssignedMembers] = useState<Record<string, string[]>>({
    "team_01": ["u1", "u2"],
    "team_02": ["u3"]
  });

  const [isNodeModalVisible, setIsNodeModalVisible] = useState(false);
  const [isAssignModalVisible, setIsAssignModalVisible] = useState(false);
  const [editingNode, setEditingNode] = useState<OrgNode | null>(null);
  const [targetKeys, setTargetKeys] = useState<string[]>([]);

  const [nodeForm] = Form.useForm();

  const filteredTreeData = useMemo(() => {
    if (!searchText) return treeData;
    const filter = (nodes: OrgNode[]): OrgNode[] => {
      return nodes.reduce((acc: OrgNode[], node) => {
        const matches = node.title.toLowerCase().includes(searchText.toLowerCase());
        const childMatches = node.children ? filter(node.children) : [];
        if (matches || childMatches.length > 0) {
          acc.push({ ...node, children: childMatches.length > 0 ? childMatches : node.children });
        }
        return acc;
      }, []);
    };
    return filter(treeData);
  }, [treeData, searchText]);

  const currentSelection = useMemo(() => {
    const findNode = (nodes: OrgNode[], key: string): OrgNode | null => {
      for (const node of nodes) {
        if (node.key === key) return node;
        if (node.children) {
          const found = findNode(node.children, key);
          if (found) return found;
        }
      }
      return null;
    };
    return selectedKeys[0] ? findNode(treeData, selectedKeys[0] as string) : null;
  }, [treeData, selectedKeys]);

  const currentMembers = useMemo(() => {
    if (!currentSelection) return [];
    const memberIds = assignedMembers[currentSelection.key] || [];
    return globalWorkerPool.filter(u => memberIds.includes(u.key));
  }, [currentSelection, assignedMembers]);

  const handleAddNode = () => {
    setEditingNode(null);
    nodeForm.resetFields();
    if (selectedKeys[0]) nodeForm.setFieldsValue({ parentId: selectedKeys[0] });
    setIsNodeModalVisible(true);
  };

  const handleSaveNode = () => {
    nodeForm.validateFields().then(values => {
      if (editingNode) {
        const updateTree = (nodes: OrgNode[]): OrgNode[] => nodes.map(n => {
          if (n.key === editingNode.key) return { ...n, title: values.title, type: values.type };
          if (n.children) return { ...n, children: updateTree(n.children) };
          return n;
        });
        setTreeData(updateTree(treeData));
        message.success(t("saved"));
      } else {
        const newNode: OrgNode = { key: `n_${Date.now()}`, title: values.title, type: values.type };
        if (values.parentId) {
          const updateTree = (nodes: OrgNode[]): OrgNode[] => nodes.map(n => {
            if (n.key === values.parentId) return { ...n, children: [...(n.children || []), newNode] };
            if (n.children) return { ...n, children: updateTree(n.children) };
            return n;
          });
          setTreeData(updateTree(treeData));
        } else {
          setTreeData([...treeData, newNode]);
        }
        message.success(t("created"));
      }
      setIsNodeModalVisible(false);
    });
  };

  const handleOpenAssignment = () => {
    if (!currentSelection) return;
    setTargetKeys(assignedMembers[currentSelection.key] || []);
    setIsAssignModalVisible(true);
  };

  const handleSaveAssignment = () => {
    if (!currentSelection) return;
    setAssignedMembers({ ...assignedMembers, [currentSelection.key]: targetKeys });
    message.success(t("memberAdded"));
    setIsAssignModalVisible(false);
  };

  const memberColumns = [
    { title: t("columns.name"), dataIndex: "name", key: "name", render: (text: string) => <Text strong>{text}</Text> },
    { title: t("columns.role"), dataIndex: "defaultRole", key: "role", render: (role: string) => <Tag color={role?.toLowerCase() === 'manager' ? 'gold' : 'blue'}>{(role || 'Worker').toUpperCase()}</Tag> },
    { title: t("columns.status"), dataIndex: "status", key: "status", render: (status: string) => <Tag color="success">{(status || 'active').toUpperCase()}</Tag> },
    {
      title: t("columns.action"), key: "action", align: "center" as const,
      render: (_: any, record: any) => (
        <Space>
          <Button size="small" type="link" onClick={() => message.info(t("msgAssign", { name: record.name }))}>{t("assignBtn")}</Button>
          <Popconfirm title={t("removeMember")} onConfirm={() => {
            const next = (assignedMembers[currentSelection!.key] || []).filter(id => id !== record.key);
            setAssignedMembers({ ...assignedMembers, [currentSelection!.key]: next });
            message.warning(t("memberRemoved"));
          }}>
            <Button size="small" type="text" danger icon={<DeleteOutlined />} />
          </Popconfirm>
        </Space>
      )
    },
  ];

  const getIcon = (type: string) => {
    if (type === "company") return <ProjectOutlined style={{ color: token.colorPrimary }} />;
    if (type === "department") return <ClusterOutlined style={{ color: token.colorWarning }} />;
    return <DeploymentUnitOutlined style={{ color: token.colorSuccess }} />;
  };

  return (
    <div style={{ padding: "0 24px 24px 24px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 20 }}>
        <div>
          <Title level={4} style={{ margin: 0 }}>{t("title")}</Title>
          <Text type="secondary" style={{ fontSize: 12 }}>{t("subtitle")}</Text>
        </div>
        <Flex vertical align="flex-end" gap={8}>
          <Breadcrumb 
            items={[
              { title: <Space><HomeOutlined /> {t("listPage.home", { ns: "labeling" })}</Space> },
              { title: t("title") }
            ]} 
          />
          <Space>
            <Input
              placeholder={t("search", { ns: "common" })}
              prefix={<SearchOutlined />}
              allowClear
              size="small"
              style={{ width: 180, borderRadius: 6 }}
              onChange={e => setSearchText(e.target.value)}
            />
            <Button type="primary" size="small" icon={<PlusOutlined />} style={{ borderRadius: 6 }} onClick={handleAddNode}>{t("addTitle")}</Button>
          </Space>
        </Flex>
      </div>

      <Row gutter={16}>
        <Col span={8}>
          <Card variant="borderless" style={{ borderRadius: 12, height: "calc(100vh - 180px)", boxShadow: token.boxShadowTertiary }} styles={{ body: { padding: "12px" } }}>
            <Tree
              showIcon
              blockNode
              defaultExpandAll
              expandedKeys={expandedKeys}
              onExpand={setExpandedKeys}
              selectedKeys={selectedKeys}
              onSelect={setSelectedKeys}
              treeData={filteredTreeData.map(node => ({
                ...node,
                icon: getIcon(node.type),
                title: <span style={{ fontWeight: selectedKeys.includes(node.key) ? 700 : 400 }}>{node.title}</span>
              }))}
              style={{ background: "transparent" }}
            />
          </Card>
        </Col>

        <Col span={16}>
          <Card
            title={currentSelection ? `${currentSelection.title} ${t("detailTitle")}` : t("detailTitle")}
            extra={currentSelection && <Button icon={<UserAddOutlined />} type="primary" size="small" onClick={handleOpenAssignment}>{t("addMember")}</Button>}
            variant="borderless"
            style={{ borderRadius: 12, height: "calc(100vh - 180px)", boxShadow: token.boxShadowTertiary }}
          >
            {currentSelection ? (
              <div style={{ height: "calc(100vh - 300px)", overflowY: "auto" }}>
                <Row gutter={16} style={{ marginBottom: 24 }}>
                  <Col span={8}><Card size="small" styles={{ body: { textAlign: "center" } }}><Text type="secondary">{t("stats.totalMembers")}</Text><Title level={4} style={{ margin: "4px 0" }}>{currentMembers.length}{t("peopleUnit", { ns: "common" })}</Title></Card></Col>
                  <Col span={8}><Card size="small" styles={{ body: { textAlign: "center" } }}><Text type="secondary">{t("stats.activeProjects")}</Text><Title level={4} style={{ margin: "4px 0" }}>{currentSelection.type === 'team' ? '12' : '3'}{t("jobUnit", { ns: "common" })}</Title></Card></Col>
                  <Col span={8}><Card size="small" styles={{ body: { textAlign: "center" } }}><Text type="secondary">{t("stats.workVolume")}</Text><Title level={4} style={{ margin: "4px 0" }}>1.2k{t("unit", { ns: "common" })}</Title></Card></Col>
                </Row>

                <Title level={5} style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 16 }}><TeamOutlined /> {t("memberList")}</Title>
                <Table
                  dataSource={currentMembers}
                  columns={memberColumns as any}
                  size="small"
                  pagination={false}
                  locale={{ emptyText: <Empty description={t("empty")} /> }}
                />
              </div>
            ) : (
              <Empty description={t("empty")} style={{ marginTop: 120 }} />
            )}
          </Card>
        </Col>
      </Row>

      <Modal title={editingNode ? t("editTitle") : t("addTitle")} open={isNodeModalVisible} onOk={handleSaveNode} onCancel={() => setIsNodeModalVisible(false)} okText={t("confirm", { ns: "common" })} destroyOnHidden>
        <Form form={nodeForm} layout="vertical" style={{ marginTop: 20 }}>
          <Form.Item name="type" label={t("typeLabel")} initialValue="team"><Select><Option value="company">{t("types.company")}</Option><Option value="department">{t("types.department")}</Option><Option value="team">{t("types.team")}</Option></Select></Form.Item>
          <Form.Item name="title" label={t("nameLabel")} rules={[{ required: true }]}><Input placeholder={t("namePlaceholder")} /></Form.Item>
          {!editingNode && <Form.Item name="parentId" label={t("parentLabel")}><Select placeholder={t("parentPlaceholder")} allowClear>{treeData.map(g => <Option key={g.key} value={g.key}>{g.title}</Option>)}</Select></Form.Item>}
        </Form>
      </Modal>

      <Modal title={`${t("addMember")} - ${currentSelection?.title}`} open={isAssignModalVisible} onOk={handleSaveAssignment} onCancel={() => setIsAssignModalVisible(false)} width={700} okText={t("confirm", { ns: "common" })} style={{ top: 50 }} destroyOnHidden>
        <div style={{ marginTop: 20 }}>
          <Transfer
            dataSource={globalWorkerPool.map(user => ({ key: user.key, title: user.name, description: user.defaultRole }))}
            showSearch
            listStyle={{ width: 300, height: 400 }}
            targetKeys={targetKeys}
            onChange={(keys) => setTargetKeys(keys as string[])}
            render={(item) => (
              <Space>
                <span>{item.title}</span>
                <Tag color={item.description?.toLowerCase() === 'manager' ? 'gold' : 'blue'} style={{ fontSize: '10px' }}>{item.description}</Tag>
              </Space>
            )}
            titles={[t("total", { ns: "common" }), t("memberList")]}
          />
        </div>
      </Modal>
    </div>
  );
}
